mapper.select:
SELECT COUNT(1)
FROM policy_application
WHERE applicant_id_no = #{applicantIdNo}
  AND insured_id_no = #{insuredIdNo}
  AND product_code = #{productCode}
  AND application_status = 'PENDING'

      AND application_id != #{applicationId}

SELECT COUNT(1)
FROM policy_application pa


        AND pa.application_id = #{applicationId}


        AND pa.applicant_id_no = #{applicantIdNo}


        AND pa.insured_id_no = #{insuredIdNo}


        AND pa.application_status = #{applicationStatus}


        AND pa.product_code = #{productCode}


        AND pa.submission_time  >=  #{submissionStartTime}


        AND pa.submission_time  <=  #{submissionEndTime}

SELECT pa.application_id AS applicationId, pa.applicant_id_no AS applicantIdNo, pa.applicant_name AS applicantName, pa.applicant_gender AS applicantGender, pa.applicant_birthdate AS applicantBirthdate, pa.insured_id_no AS insuredIdNo, ip.insured_name AS insuredName, ip.insured_gender AS insuredGender, ip.insured_birthdate AS insuredBirthdate, ip.contact_phone AS contactPhone, pa.product_code AS productCode, p.name AS productName, pa.application_status AS applicationStatus, pa.relationship_to_insured AS relationshipToInsured, pa.sum_insured AS sumInsured, pa.annual_premium AS annualPremium, pa.submission_time AS submissionTime, pa.review_time AS reviewTime, pa.reviewed_by AS reviewedBy, pa.rejection_reason AS rejectionReason, pa.created_by AS createdBy FROM policy_application pa INNER JOIN insured_person ip ON pa.application_id = ip.application_id INNER JOIN product p ON pa.product_code = p.code
AND pa.application_id = #{applicationId}
AND pa.applicant_id_no = #{applicantIdNo}
AND pa.insured_id_no = #{insuredIdNo}
AND pa.application_status = #{applicationStatus}
AND pa.product_code = #{productCode}
AND pa.submission_time >= #{submissionStartTime}
AND pa.submission_time <= #{submissionEndTime}
ORDER BY pa.submission_time
ASC
DESC
LIMIT #{offset}, #{pageSize}
